import{_ as a,o as n,c as t,ae as i}from"./chunks/framework.B6gjLfeO.js";const u=JSON.parse('{"title":"Email Integration for Developers","description":"","frontmatter":{"title":"Email Integration for Developers","slug":"email-integration-for-developers"},"headers":[],"relativePath":"developer-hub/email-integration-for-developers.md","filePath":"developer-hub/email-integration-for-developers.md"}'),r={name:"developer-hub/email-integration-for-developers.md"};function o(s,e,l,c,p,h){return n(),t("div",null,[...e[0]||(e[0]=[i(`<p>This guide covers the technical prerequisites and implementation details for integrating Branch Email. Marketers should refer to our Email integration guide for marketers for dashboard configuration and campaign setup.</p><h2 id="email-integration-prerequisites" tabindex="-1">Email integration prerequisites <a class="header-anchor" href="#email-integration-prerequisites" aria-label="Permalink to &quot;Email integration prerequisites&quot;">​</a></h2><p>Before your marketing team can configure Branch Email in the dashboard, you must complete the following technical prerequisites in your app and infrastructure.</p><ol><li><p><a href="https://dashboard.branch.io/configuration/general" target="_blank" rel="noreferrer">Add deep link routing &amp; required redirects</a>.</p></li><li><p><a href="./native-sdks-overview.html">Implement the Branch SDK</a>.</p></li><li><p><a href="./ios-universal-links.html">Enable Universal Linking</a>.</p></li><li><p><a href="./ios-basic-integration.html#3-configure-associated-domains">Add your ESP&#39;s CTD to your Associated Domains Entitlement</a>.</p><ol><li>Verify it is valid using our <a href="https://branch.io/resources/aasa-validator" target="_blank" rel="noreferrer">AASA file Validator</a>.</li></ol></li><li><p><a href="./ios-advanced-features.html#web-only-content">Add handle web-only content app code</a>.</p></li><li><p><a href="./ios-full-reference.html#continueuseractivity">Add return YES to continueUserActivity</a>.</p></li></ol><h2 id="dns-cname-configuration" tabindex="-1">DNS CNAME configuration <a class="header-anchor" href="#dns-cname-configuration" aria-label="Permalink to &quot;DNS CNAME configuration&quot;">​</a></h2><p>The majority of ESP integrations require updating the DNS record for your click tracking domain (CTD) to include a CNAME (alias) record that points to Branch&#39;s <code>thirdparty.bnc.lt</code> domain.</p><p>Please follow your web hosting provider&#39;s instructions on how to configure your DNS CNAME. Here are a few common provider&#39;s instructions for reference:</p><ul><li><a href="https://docs.aws.amazon.com/Route53/latest/DeveloperGuide/resource-record-sets-creating.html" target="_blank" rel="noreferrer">AWS</a></li><li><a href="https://www.godaddy.com/help/change-a-cname-record-19237" target="_blank" rel="noreferrer">GoDaddy</a></li><li><a href="https://support.cloudflare.com/hc/en-us/articles/360020615111-Configuring-a-CNAME-setup" target="_blank" rel="noreferrer">CloudFlare DNS</a></li></ul><h3 id="important-cname-information" tabindex="-1">Important CNAME information <a class="header-anchor" href="#important-cname-information" aria-label="Permalink to &quot;Important CNAME information&quot;">​</a></h3><ul><li>The Branch Dashboard must be enabled &amp; reflect the CTD <strong>after</strong> you add the CNAME.</li><li>If the CTD already has SSL setup, confirm if your security credentials allow a 3rd party to submit a CSR on behalf of the domain. If not, contact Branch&#39;s Support team to coordinate providing an SSL certificate manually to Branch.</li><li>Once the CNAME is added, Branch auto-generates an SSL certificate and AASA file for your click tracking domain. It may take up to an hour to resolve SSL errors once you change the CNAME. During this time, link redirects on the click tracking domain will redirect to the <strong>Default URL</strong> you provided in the <strong>General Configuration</strong> section of your account.</li><li>If you are making this change to a live domain with active email click traffic, schedule the CNAME change to occur during an off-hours time with low click traffic.</li></ul><h2 id="integration-validation" tabindex="-1">Integration validation <a class="header-anchor" href="#integration-validation" aria-label="Permalink to &quot;Integration validation&quot;">​</a></h2><p>Once the SSL certificates and AASA file (iOS only) have been generated, you can proceed to reviewing the validation tests and fixing any issues.</p><p>Branch automatically validates the following:</p><ul><li>iOS SDK is integrated (<strong>required</strong>)</li><li>Android SDK is integrated (<strong>required</strong>)</li><li>Deep linking is setup (<strong>required</strong>)</li><li>Click Tracking Domain is setup (<strong>required</strong>)</li><li>AASA file is valid (<strong>required</strong>) - Use our AASA File Validator: <a href="https://branch.io/resources/aasa-validator/" target="_blank" rel="noreferrer">https://branch.io/resources/aasa-validator/</a></li><li>SSL is correctly setup (<strong>required</strong>)</li><li>CNAME points to thirdparty.bnc.lt (<strong>case-by-case</strong> requirement)</li><li>Universal Linking is setup (<strong>required</strong>)</li><li>Hosted deep link data (optional)</li><li>App Events being tracked (optional)</li><li>Android App Links (optional)</li></ul><h3 id="common-validation-issues" tabindex="-1">Common validation issues <a class="header-anchor" href="#common-validation-issues" aria-label="Permalink to &quot;Common validation issues&quot;">​</a></h3><h4 id="cname-does-not-point-to-branch" tabindex="-1">CNAME does not point to Branch <a class="header-anchor" href="#cname-does-not-point-to-branch" aria-label="Permalink to &quot;CNAME does not point to Branch&quot;">​</a></h4><p>Pointing your DNS CNAME to Branch is a vital step of the integration process.</p><p>Please make sure to:</p><p>Log into your DNS provider&#39;s console and add the CNAME record as described above.</p><p>Wait at least 60 minutes after you&#39;ve added the CNAME record so that it has time to propagate and Branch can create the resulting SSL certificates and AASA files (for iOS apps only).</p><h4 id="ssl-not-correctly-set-up" tabindex="-1">SSL not correctly set up <a class="header-anchor" href="#ssl-not-correctly-set-up" aria-label="Permalink to &quot;SSL not correctly set up&quot;">​</a></h4><p>If you are having issues with the SSL certificate validating, the culprit is generally the fact that your click tracking domain already has SSL set up and there are restrictions that prevent a 3rd party from submitting a Certificate Signing Request on your behalf.</p><h4 id="aasa-file-is-invalid" tabindex="-1">AASA file is invalid <a class="header-anchor" href="#aasa-file-is-invalid" aria-label="Permalink to &quot;AASA file is invalid&quot;">​</a></h4><p>The main reason for this error is the fact that it depends on the SSL being set up correctly. By addressing the SSL error, the AASA file error should resolve itself simultaneously.</p><h2 id="how-to-open-emails-in-android-to-support-web-only-use-case" tabindex="-1">How to open emails in Android to support web-only use case <a class="header-anchor" href="#how-to-open-emails-in-android-to-support-web-only-use-case" aria-label="Permalink to &quot;How to open emails in Android to support web-only use case&quot;">​</a></h2><p>There are 2 options to support the web-only use case in Android to open a Branch Email link:</p><ol><li><p>Remove the CTD from the manifest file, this will let all the links coming from the email to open as web_only. In cases where the apps need to open after clicking the Branch Link, URI scheme would serve that use case.</p></li><li><p>If you want to use applinks and still have the email links open web_only, then add the following code in the Android app to support the web_only logic.</p></li></ol><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>@Override</span></span>
<span class="line"><span>public void onStart() {</span></span>
<span class="line"><span>    super.onStart();</span></span>
<span class="line"><span>    Branch.getInstance().initSession(new Branch.BranchReferralInitListener() {</span></span>
<span class="line"><span>        @Override</span></span>
<span class="line"><span>        public void onInitFinished(JSONObject referringParams, BranchError error) {</span></span>
<span class="line"><span>            if (error == null) {</span></span>
<span class="line"><span>                //logic to handle webonly routing</span></span>
<span class="line"><span>                String webOnlyParam = referringParams.optString(&quot;$web_only&quot;);</span></span>
<span class="line"><span>                if(!webOnlyParam.isEmpty()) {</span></span>
<span class="line"><span>                    if(webOnlyParam.contentEquals(&quot;true&quot;)) {</span></span>
<span class="line"><span>                        String url = referringParams.optString(&quot;$canonical_url&quot;);</span></span>
<span class="line"><span>                        if(!url.isEmpty()) {</span></span>
<span class="line"><span>                            Intent i = new Intent(Intent.ACTION_VIEW);</span></span>
<span class="line"><span>                            i.setData(Uri.parse(url));</span></span>
<span class="line"><span>                            startActivity(i);</span></span>
<span class="line"><span>                        } else {</span></span>
<span class="line"><span>                            Log.i(&quot;Tag&quot;,&quot;missing $canonical_url&quot;);</span></span>
<span class="line"><span>                        }</span></span>
<span class="line"><span>                    }</span></span>
<span class="line"><span>                } else {</span></span>
<span class="line"><span>                    //Logic to handle routing in app</span></span>
<span class="line"><span>                }</span></span>
<span class="line"><span>            }</span></span>
<span class="line"><span>        }</span></span>
<span class="line"><span>    }, this.getIntent().getData(), this);</span></span>
<span class="line"><span>}</span></span></code></pre></div><h2 id="faqs" tabindex="-1">FAQs <a class="header-anchor" href="#faqs" aria-label="Permalink to &quot;FAQs&quot;">​</a></h2><details><summary>What do the Email validation errors/warnings mean and how can I fix them?</summary><p>Here&#39;s the explanation and fix for all the validation errors:</p><ol><li><strong>iOS SDK is not integrated</strong>: This error is thrown when the Branch SDK has not been integrated into the iOS app.<br><em>Fix: You need to set up the iOS SDK as our official documentation.</em></li><li><strong>iOS SDK is integrated but is not the latest version. This may affect email functionality.</strong>: This warning is thrown when the Branch SDK version on iOS is lower than the latest version.<br><em>Fix: Update the Branch iOS SDK</em></li><li><strong>Android SDK is not integrated</strong>: This error is thrown when the Branch SDK has not been integrated into the Android app.<br><em>Fix: You need to set up the Android SDK as our official documentation.</em></li><li><strong>Android SDK is integrated but is not the latest version. This may affect email functionality.</strong>: This warning is thrown when the Branch SDK version on Android is lower than the latest version.<br><em>Fix: Update the Branch Android SDK</em></li><li><strong>Deep linking is not set up for email</strong>: The following are all the possible settings you can configure for deep linking with email. To understand each of the settings you can read our documentation <a href="./branch-universal-email.html">here</a>.</li><li><strong>Click tracking domain is not set</strong>: For Branch Links to be generated, you would need to provide the domain of the link that would be used in the email template. To understand how to find your ESP&#39;s click tracking domain, you can read our documentation <a href="./universal-email-integration-guide.html">here</a>.</li><li><strong>AASA is invalid</strong>: If you have not set up the Universal Links in the app, you&#39;ll get this error. This is mandatory for Deep Linked Emails to work on iOS.<br><em>Fix: You can setup Universal Link by following our documentation</em> <a href="./ios-universal-links.html"><em>here</em></a><em>.</em></li><li><strong>CNAME points to thirdparty.bnc.lt:</strong> For Branch to host your AASA file and generate SSL certificates on the link domain for the email, you are required to CNAME the domain to thirdparty.bnc.lt. Before making this change, please make sure your setup requires this as some ESP have an option to upload the AASA at their end. Please verify this step in the documentation for your ESP <a href="./universal-email-integration-guide.html#4-point-dns-cname-to-branch">here</a>.</li><li><strong>SSL is not correctly set up</strong>: Once you setup the email domain on the Branch dashboard and CNAME as per the step 6, we would provide an SSL certificate to host your AASA file over HTTPS. Please contact <a href="mailto:support@branch.io" target="_blank" rel="noreferrer">support@branch.io</a> if you find the SSL certificate is not issued. This step is only required if error 8 is valid for your ESP.</li><li><strong>Deep link data is hosted on your website</strong>: We recommend using the Hosted Meta Data on the web pages for deep linking. This helps in auto-generating the link data for emails in the Branch Links. To learn about hosting metadata for Branch, you can follow our documentation <a href="./web-advanced-features.html">here</a>.</li><li><strong>Revenue or custom events are tracked</strong>: This is a recommend in-app setup to track the revenue and the custom events which can be attributed to the Branch Link generated in the emails.</li><li><strong>Universal/App Links are not configured</strong>: We strongly recommend setting up the Universal Links for iOS and App Links for Android to launch the app directly from the emails.</li></ol></details><details><summary>Why do all my links redirect to https://branch.io when I add CNAME to them?</summary><p>Once the CNAME is added, Branch auto-generates an SSL certificate and AASA file for your click tracking domain. It may take up to an hour to resolve SSL errors once you change the CNAME. During this time, link redirects on the click tracking domain will redirect to <a href="https://branch.io" target="_blank" rel="noreferrer">https://branch.io</a>.</p><p>If you are making this change to a live domain with active email click traffic, schedule the CNAME change to occur during off-hours with low click traffic.</p></details>`,31)])])}const m=a(r,[["render",o]]);export{u as __pageData,m as default};
